document.addEventListener('DOMContentLoaded',()=>{console.log('Sil Almeida Store initialized.');const products=[{id:1,name:"Boa, Perfeita e Agradável é a vontade do Senhor",image:"images/fotos/boa-perfeita-e-agradavel-e-a-vontade-do-senhor.webp",meta:"Confie nos planos de Deus"},{id:2,name:"As Promessas de Deus",image:"images/fotos/as-promessas-frente.webp",meta:"Acredite nas promessas de Deus"},{id:3,name:"As Promessas de Deus",image:"images/fotos/as-promessas-costas.webp",meta:"Espere com fé, Deus cumpre"},{id:4,name:"Ca/Fé",image:"images/fotos/cafe-ca-fe.webp",meta:"Viva sua fé nos detalhes"},{id:5,name:"Das minhas feridas, flores fez nascer",image:"images/fotos/das-minhas-feridas-flores-fez-nascer.webp",meta:"Permita que Deus transforme sua dor"},{id:6,name:"Deixa que Deus cuida de tudo",image:"images/fotos/deixa-que-deus-cuida-de-tudo.webp",meta:"Entregue tudo nas mãos de Deus"},{id:7,name:"Deus é Bom o Tempo Todo",image:"images/fotos/deus-e-bom-o-tempo-todo.webp",meta:"Reconheça a bondade de Deus"},{id:8,name:"Gratidão por Tudo",image:"images/fotos/gratidao-por-tudo.webp",meta:"Agradeça em todos os momentos"},{id:9,name:"Há um Tempo para todo Propósito",image:"images/fotos/ha-um-tempo-para-todo-proposito.webp",meta:"Respeite o tempo de Deus"},{id:10,name:"Jesus",image:"images/fotos/jesus-frente.webp",meta:"Declare o nome de Jesus"},{id:11,name:"Jesus",image:"images/fotos/jesus-costa.webp",meta:"Jesus te Ama"},{id:12,name:"Jesus é a Causa da minha Felicidade",image:"images/fotos/jesus-e-a-causa-da-minha-felicidade.webp",meta:"Encontre alegria em Jesus"},{id:13,name:"Jesus Salva",image:"images/fotos/jesus-salva.webp",meta:"Creia que Jesus salva"},{id:14,name:"Porque d'Ele e por Ele, e para Ele são todas as coisas, amém",image:"images/fotos/porque-dele-e-por-ele-e-para-ele-sao-todas-as-coisas-amem.webp",meta:"Reconheça Deus em tudo"},{id:15,name:"Tu és o Deus que me vê",image:"images/fotos/tu-es-o-deus-que-me-ve.webp",meta:"Lembre-se, Deus vê você"},{id:16,name:"Um dia de cada vez, e Jesus em todos",image:"images/fotos/um-dia-de-cada-vez-e-jesus-em-todos.webp",meta:"Viva um dia de cada vez com fé"}];const createSlideHTML=(product,index)=>`
        <img src="${product.image}" alt="${product.name}" class="hero-image">
        <button class="drawer-trigger" aria-label="Ver detalhes">
            <i class="ph ph-plus"></i>
        </button>
        <div class="product-drawer">
            <div class="drawer-header">
                <div class="drawer-handle"></div>
                <button class="drawer-close"><i class="ph ph-x"></i></button>
            </div>
            <div class="drawer-content">
                <h3 class="product-name">${product.name}</h3>
                <p class="product-meta">${product.meta}</p>
                <div class="size-selection">
                    <span class="size-label">Escolha o tamanho:</span>
                    <div class="size-options">
                        ${['P','M','G','GG','XG'].map(size=>`
                            <label class="size-option">
                                <input type="radio" name="size-${index}" value="${size}" ${size==='M'?'checked':''}>
                                <span class="size-chip">${size}</span>
                            </label>
                        `).join('')}
                    </div>
                </div>
                <button class="btn btn-primary btn-full btn-order" data-name="${product.name}">
                    <i class="ph ph-whatsapp-logo"></i> Encomendar
                </button>
            </div>
        </div>
    `;const renderProducts=(selector)=>{const wrapper=document.querySelector(`${selector} .swiper-wrapper`);if(wrapper){products.forEach((product,index)=>{const slide=document.createElement('div');slide.className='swiper-slide';slide.innerHTML=createSlideHTML(product,selector.includes('modal')?`m-${index}`:`h-${index}`);wrapper.appendChild(slide);});}};renderProducts('.hero-swiper');renderProducts('.modal-swiper');const closeAllDrawers=()=>{document.querySelectorAll('.product-drawer.active').forEach(drawer=>{drawer.classList.remove('active');});};const heroSwiper=new Swiper('.hero-swiper',{direction:'vertical',slidesPerView:1,spaceBetween:0,centeredSlides:true,loop:true,speed:800,mousewheel:true,keyboard:{enabled:true},pagination:{el:'.custom-pagination',clickable:true},observer:true,observeParents:true,on:{slideChange:closeAllDrawers}});const modalSwiper=new Swiper('.modal-swiper',{direction:'vertical',slidesPerView:1,spaceBetween:0,centeredSlides:true,loop:true,speed:800,mousewheel:true,keyboard:{enabled:true},pagination:{el:'.modal-pagination',clickable:true},observer:true,observeParents:true,on:{slideChange:closeAllDrawers}});const catalogModal=document.getElementById('catalogModal');const btnCatalog=document.querySelector('.btn-catalog');const btnCloseCatalog=document.querySelector('.modal-catalog-close');if(catalogModal&&btnCatalog&&btnCloseCatalog){btnCatalog.addEventListener('click',(e)=>{e.preventDefault();catalogModal.classList.add('active');document.body.style.overflow='hidden';setTimeout(()=>{modalSwiper.update();},300);});btnCloseCatalog.addEventListener('click',()=>{catalogModal.classList.remove('active');document.body.style.overflow='';});}const arrowUp=document.querySelector('.arrow-up');const arrowDown=document.querySelector('.arrow-down');if(arrowUp&&arrowDown){arrowUp.addEventListener('click',()=>heroSwiper.slidePrev());arrowDown.addEventListener('click',()=>heroSwiper.slideNext());}document.addEventListener('click',(e)=>{const trigger=e.target.closest('.drawer-trigger');const closeBtn=e.target.closest('.drawer-close');const orderBtn=e.target.closest('.btn-order');if(trigger){closeAllDrawers();const drawer=trigger.nextElementSibling;drawer.classList.add('active');}if(closeBtn){const drawer=closeBtn.closest('.product-drawer');drawer.classList.remove('active');}if(orderBtn){const productName=orderBtn.getAttribute('data-name');const drawer=orderBtn.closest('.product-drawer');const selectedSize=drawer.querySelector('input[type="radio"]:checked')?.value||'M';const phoneNumber="5527998307531";const message=`Olá! estou no site e gostei do modelo:
- ${productName}.
Tem tamanho [${selectedSize}]?`;const waUrl=`https://wa.me/${phoneNumber}?text=${encodeURIComponent(message)}`;window.open(waUrl,'_blank');}});const aboutModal=document.getElementById('aboutModal');const openModalBtn=document.getElementById('openModal');const closeModalBtn=document.querySelector('.modal-close');if(aboutModal&&openModalBtn&&closeModalBtn){openModalBtn.addEventListener('click',()=>{aboutModal.classList.add('active');document.body.style.overflow='hidden';});const closeModal=()=>{aboutModal.classList.remove('active');document.body.style.overflow='';};closeModalBtn.addEventListener('click',closeModal);aboutModal.addEventListener('click',(e)=>{if(e.target===aboutModal)closeModal();});}});
